#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Function to swap two characters
void swap(char *a, char *b) {
    char temp = *a;
    *a = *b;
    *b = temp;
}

// Function to generate all permutations of a string
void permute(char *str, int left, int right) {
    if (left == right)
        printf("%s\n", str);
    else {
        for (int i = left; i <= right; i++) {
            swap((str + left), (str + i));
            permute(str, left + 1, right);
            swap((str + left), (str + i)); // backtrack
        }
    }
}

// Function to convert a number from base X to decimal
int baseToDecimal(char *num, int base) {
    int decimal = 0;
    int power = 1;
    for (int i = strlen(num) - 1; i >= 0; i--) {
        decimal += (num[i] - '0') * power;
        power *= base;
    }
    return decimal;
}

// Function to check if the sum of two numbers equals a third number
int checkSum(char *A, char *B, char *C, int X) {
    int sum = baseToDecimal(A, X) + baseToDecimal(B, X);
    return sum == baseToDecimal(C, X);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int X;
        char A[100], B[100], C[100];
        scanf("%d %s %s %s", &X, A, B, C);
        int count = 0;
        int lenA = strlen(A);
        int lenB = strlen(B);
        permute(A, 0, lenA - 1);
        permute(B, 0, lenB - 1);
        // Convert to base X and check sum
        if (checkSum(A, B, C, X))
            count++;
        printf("%d\n", count);
    }
    return 0;
}

