import sys
import itertools

def permute(s):
    return [''.join(p) for p in itertools.permutations(s)]

def base_to_decimal(num, base):
    decimal = 0
    power = 1
    for i in range(len(num) - 1, -1, -1):
        decimal += int(num[i]) * power
        power *= base
    return decimal

def check_sum(A, B, C, X):
    sum = base_to_decimal(A, X) + base_to_decimal(B, X)
    return sum == base_to_decimal(C, X)

def main():
    T = int(sys.stdin.readline().strip())
    for _ in range(T):
        X, A, B, C = sys.stdin.readline().strip().split()
        X = int(X)
        count = 0
        perms_A = permute(A)
        perms_B = permute(B)
        for a in perms_A:
            for b in perms_B:
                if check_sum(a, b, C, X):
                    count += 1
        print(count)
if __name__ == '__main__':
    main()

